import '../Styles/HistogramStyles.css';
import { Component } from 'preact';
import DropdownButton from 'react-bootstrap/DropdownButton';
import Dropdown from 'react-bootstrap/Dropdown';

class HistogramComponent extends Component {

  constructor(props){
    super(props)
    this.state = {
      datos:[], //Datos dibujados en el starplot
      flag:1, //Flag para trasladar los puntos con respecto a los ejes del starplot una unica vez
      titleDropDown:"SiO2",
      optionDropDown : 0, //opcion seleccionada del dropdownbutton
    }
    this.update_histogram = this.update_histogram.bind(this);
  }

  //se invoca antes de renderizar cuando se reciben nuevas propiedades o estados
  componentWillReceiveProps(nextProps) {
    if(!(this.props.data != nextProps.data)){
      this.update_histogram(nextProps);
    }
  }

  //Modifica el estado al seleccionar una opcion en dropdown
  onSelect_dropdown(evt){
    const options = ["SiO2","TiO2","V2O5","Al2O3","Cr2O3","FeO","Fe2O3","MnO","MgO","NiO","ZnO"];
    this.props.callback_dropDownOption(parseInt(evt));
    this.setState({titleDropDown:options[parseInt(evt)]});
    this.setState({optionDropDown:parseInt(evt)},()=>this.update_histogram(this.props));
  }

  /*
  * Método para dibujar el Starplot
  */
  update_histogram(props){
    var canvas = document.getElementById("background"),
    context = canvas.getContext("2d");

    d3.select("#container").select("svg").remove(); //remuevo el contenido

    var margin = {top: 20, right: 20, bottom: 30, left: 50},
    width = canvas.width - margin.left - margin.right,
    height = canvas.height - margin.top - margin.bottom;

    var data=[];
    var datos = props.data;
    for(let i=0; i< props.selected_data.length; i++){
      data.push({
        SiO2: +datos[props.selected_data[i]].SiO2,
        TiO2: +datos[props.selected_data[i]].TiO2,
        V2O3: +datos[props.selected_data[i]].V2O3,
        Al2O3: +datos[props.selected_data[i]].Al2O3,
        Cr2O3: +datos[props.selected_data[i]].Cr2O3,
        FeO: +datos[props.selected_data[i]].FeO,
        Fe2O3: +datos[props.selected_data[i]].Fe2O3,
        MnO: +datos[props.selected_data[i]].MnO,
        MgO: +datos[props.selected_data[i]].MgO,
        NiO: +datos[props.selected_data[i]].NiO,
        ZnO: +datos[props.selected_data[i]].ZnO,
      });
    }

    var scaleColor = d3.scaleOrdinal()
      .domain(["Alaskan ultramafic","Alkali/Lamprophyres","Basalt","Komatiite","Laterite","Layered intrusion","Metamorphic","Ophiolite","Xenoliths"])
      //.range(["#4D69DC","#9e0142", "#e95c47", "#fdbf6f", "#ffffbe", "#bfe5a0", "#54aead", "#5e4fa2", "#DC4DD8"])
      .range(["#7986cb","#f06292", "#ff8a65", "#ffb74d", "#fff176", "#aed581", "#4db6ac","#64b5f6", "#ba68c8"]);

    let distribution=[];
    for(let i = 0; i<data.length; i++){
      distribution.push(data[i].SiO2);
    }


    let svg = d3.select("#container").append("svg")
          .attr("width", width + margin.left + margin.right)
          .attr("height", height + margin.top + margin.bottom)
          .attr("transform", "translate(" + margin.left + "," + margin.top + ")")

    var x = d3.scaleLinear()
      .domain([0, 1])
      .range([margin.left, width - margin.right]);

    var y = d3.scaleLinear()
        .domain([0, 1])
        .range([height - margin.bottom, margin.top]);

    svg.append("g")
        .attr("class", "axis axis--x")
        .attr("transform", "translate(0," + (height - margin.bottom) + ")")
        .call(d3.axisBottom(x))
      .append("text")
        .attr("x", width - margin.right)
        .attr("y", 0)
        .attr("fill", "#000")
        .attr("text-anchor", "end")
        .attr("font-weight", "bold")
        .text("x");

    svg.append("g")
        .attr("class", "axis axis--y")
        .attr("transform", "translate(" + margin.left + ",0)")
        .call(d3.axisLeft(y).ticks(null, "%"));

    var n = distribution.length,
        bins = d3.histogram().domain(x.domain()).thresholds(10)(distribution);
        //density = kernelDensityEstimator(kernelEpanechnikov(1), x.ticks(10))(faithful);

    svg.insert("g", "*")
        .attr("fill", "#bbb")
        .selectAll("rect")
        .data(bins)
        .enter().append("rect")
          .attr("x", function(d) { return x(d.x0) + 1; })
          .attr("y", function(d) { return y(d.length / n); })
          .attr("width", function(d) { return x(d.x1) - x(d.x0) - 1; })
          .attr("height", function(d) { return y(0) - y(d.length / n); });

/*
    svg.append("path")
        .datum(density)
        .attr("fill", "none")
        .attr("stroke", "#000")
        .attr("stroke-width", 1.5)
        .attr("stroke-linejoin", "round")
        .attr("d",  d3.line()
            .curve(d3.curveBasis)
            .x(function(d) { return x(d[0]); })
            .y(function(d) { return y(d[1]); }));*/

    function kernelDensityEstimator(kernel, X) {
        return function(V) {
          return X.map(function(x) {
            return [x, d3.mean(V, function(v) { return kernel(x - v); })];
          });
        };
    }

/*
    function kernelEpanechnikov(k) {
          return function(v) {
              return Math.abs(v /= k) <= 1 ? 0.75 * (1 - v * v) / k : 0;
          };
      }*/
  }


  render(){
    const axes = ["SiO2","TiO2","V2O5","Al2O3","Cr2O3","FeO","Fe2O3","MnO","MgO","NiO","ZnO"];
    const display = this.props.selected_data.length>0 ? "inline":"none";
    return (
      <div>
        <div id="container" class="container-Histogram">
          <canvas id="background" width="500" height="500"></canvas>
        </div>
        <div id="dropdown-basic-button-histogram" style={{display:display}}  >
          <DropdownButton title={this.state.titleDropDown} onSelect={(e)=>this.onSelect_dropdown(e)}>
            <Dropdown.Item eventKey={0}>SiO2</Dropdown.Item>
            <Dropdown.Item eventKey={1}>TiO2</Dropdown.Item>
            <Dropdown.Item eventKey={2}>V2O5</Dropdown.Item>
            <Dropdown.Item eventKey={3}>Al2O3</Dropdown.Item>
            <Dropdown.Item eventKey={4}>Cr2O3</Dropdown.Item>
            <Dropdown.Item eventKey={5}>FeO</Dropdown.Item>
            <Dropdown.Item eventKey={6}>Fe2O3</Dropdown.Item>
            <Dropdown.Item eventKey={7}>MnO</Dropdown.Item>
            <Dropdown.Item eventKey={8}>MgO</Dropdown.Item>
            <Dropdown.Item eventKey={9}>NiO</Dropdown.Item>
            <Dropdown.Item eventKey={10}>ZnO</Dropdown.Item>
          </DropdownButton>
        </div>
      </div>
   );
  }

}
export default HistogramComponent;
